import { medicalDatabase } from "@/lib/medicalData";

export async function POST(req: Request) {
  try {
    const body = await req.json();
    // Use the original message for the prompt, convert to lowercase for searching
    const originalMessage = body.message || "";
    const message = originalMessage.toLowerCase();

    const apiKey = process.env.GEMINI_API_KEY;

    if (!apiKey) {
      console.error("Missing GEMINI_API_KEY");
      return Response.json({
        reply: "Server configuration error: API key missing"
      });
    }

    // Step 3: Detect symptoms
    let matchedCondition = null;
    for (const condition of medicalDatabase) {
      if (condition.keywords.some(keyword => message.includes(keyword.toLowerCase()))) {
        matchedCondition = condition;
        break;
      }
    }

    // Preserve dynamic model selection
    const modelFetchParams = await fetch(
      "https://generativelanguage.googleapis.com/v1beta/models?key=" + apiKey
    );
    const modelsData = await modelFetchParams.json();
    
    let targetModel = "gemini-pro"; 

    if (modelsData && modelsData.models) {
      const supported = modelsData.models
        .filter((m: any) => m.supportedGenerationMethods?.includes("generateContent"))
        .map((m: any) => m.name.replace('models/', ''));

      if (supported.includes("gemini-1.5-flash")) targetModel = "gemini-1.5-flash";
      else if (supported.includes("gemini-1.5-pro")) targetModel = "gemini-1.5-pro";
      else if (supported.includes("gemini-1.0-pro")) targetModel = "gemini-1.0-pro";
      else if (supported.includes("gemini-pro")) targetModel = "gemini-pro";
      else if (supported.length > 0) targetModel = supported[0];
    }

    const callGemini = async (prompt: string) => {
      try {
        const response = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${targetModel}:generateContent?key=${apiKey}`,
          {
            method: "POST",
            headers: {
              "Content-Type": "application/json"
            },
            body: JSON.stringify({
              contents: [
                {
                  parts: [
                    { text: prompt }
                  ]
                }
              ]
            })
          }
        );

        const data = await response.json();

        if (response.ok && data?.candidates?.[0]?.content?.parts?.[0]?.text) {
          return data.candidates[0].content.parts[0].text;
        }
        return null;
      } catch (err) {
        console.error("Gemini call error:", err);
        return null;
      }
    };

    if (matchedCondition) {
      // Step 4: Structuring response
      let reply = `Suggested Medicine:\n${matchedCondition.medicine}\n\nDosage:\n${matchedCondition.dosage}\n\nAdvice:\n${matchedCondition.advice}\n\nNote:\nIf symptoms persist for more than 2 days, consult a doctor.`;

      const prompt = `Explain why ${matchedCondition.medicine} works for ${matchedCondition.keywords.join(" or ")} and when to avoid it. Keep it simple, brief and easy to understand for a rural user.`;
      
      const explanation = await callGemini(prompt);
      
      if (explanation) {
        reply += `\n\nAdditional Info:\n${explanation}`;
      }

      return Response.json({ reply });
    } else {
      // Step 5: Fallback to AI
      const prompt = `You are a basic healthcare assistant for rural users.
Provide simple, safe, and practical advice.
Do not suggest strong or prescription medicines.
Always recommend doctor consultation for serious symptoms.

User: ${originalMessage}`;
      
      const fallbackResponse = await callGemini(prompt);
      
      if (fallbackResponse) {
        return Response.json({ reply: fallbackResponse });
      } else {
        // Step 6: Error Handling
        return Response.json({ reply: "Service temporarily unavailable. Please try again." });
      }
    }

  } catch (error) {
    console.error("Route error block:", error);
    return Response.json({
      reply: "Service temporarily unavailable. Please try again."
    });
  }
}

'use client';

import { useState, useEffect } from 'react';
import { db } from '../../lib/firebase';
import { collection, getDocs } from 'firebase/firestore';

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  [key: string]: any;
}

export default function AdminDashboard() {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    const fetchUsers = async () => {
      const usersCollection = await getDocs(collection(db, 'users'));
      setUsers(usersCollection.docs.map(doc => ({ id: doc.id, ...doc.data() } as User)));
    };
    fetchUsers();
  }, []);

  const filteredUsers = users.filter(user =>
    user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-slate-50 relative overflow-hidden">
      {/* Background Texture */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #000 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
      
      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <header className="mb-10">
          <h1 className="text-4xl font-extrabold text-slate-800 tracking-tight mb-2">
            Administrator <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">Portal</span>
          </h1>
          <p className="text-slate-500 text-lg">Manage platform users and role assignments</p>
        </header>

        {/* Stats Section */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
          <div className="bg-white rounded-2xl p-6 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 flex items-center gap-4 transition-transform hover:-translate-y-1 duration-300">
            <div className="w-14 h-14 rounded-full bg-blue-50 flex items-center justify-center text-blue-600">
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z"></path></svg>
            </div>
            <div>
              <p className="text-sm font-medium text-slate-500">Total Users</p>
              <p className="text-3xl font-bold text-slate-800">{users.length}</p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <h2 className="text-xl font-bold text-slate-800">User Directory</h2>
            <div className="relative">
              <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
              <input
                type="text"
                placeholder="Search by name or email"
                className="pl-10 pr-4 py-2.5 w-full sm:w-80 bg-slate-50 border-none rounded-xl text-slate-700 focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all shadow-inner"
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50/50 text-slate-500 text-sm uppercase tracking-wider">
                  <th className="px-6 py-4 font-medium">Name</th>
                  <th className="px-6 py-4 font-medium">Email</th>
                  <th className="px-6 py-4 font-medium text-center">Role</th>
                  <th className="px-6 py-4 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredUsers.map(user => (
                  <tr key={user.id} className="hover:bg-slate-50/80 transition-colors group">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-100 to-blue-100 flex items-center justify-center text-indigo-700 font-bold uppercase">
                          {(user.name || '?').charAt(0)}
                        </div>
                        <span className="font-semibold text-slate-700">{user.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-500">{user.email}</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold
                        ${user.role === 'admin' ? 'bg-red-100 text-red-700' : 
                          user.role === 'doctor' ? 'bg-emerald-100 text-emerald-700' : 
                          'bg-blue-100 text-blue-700'}`}>
                        {user.role}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-slate-400 hover:text-blue-600 transition-colors p-2 rounded-lg hover:bg-blue-50 opacity-0 group-hover:opacity-100 focus:opacity-100">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredUsers.length === 0 && (
              <div className="p-12 text-center text-slate-500">
                No users found matching your search.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

