'use client';

import { useAuth } from '../../lib/auth'; // We will create this hook
import AdminDashboard from './AdminDashboard';
import DoctorDashboard from './DoctorDashboard';
import PatientDashboard from './PatientDashboard';

export default function Dashboard() {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <div className="w-16 h-16 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin shadow-lg mb-4"></div>
        <p className="text-lg font-medium text-slate-500 animate-pulse">Loading securely...</p>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-6 text-center">
        <div className="bg-white p-8 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] max-w-sm w-full border border-slate-100">
          <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Access Denied</h2>
          <p className="text-slate-500 mb-8">Please log in to continue to the dashboard.</p>
          <a href="/login" className="block w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-xl transition-all hover:shadow-[0_0_20px_rgba(37,99,235,0.3)]">
            Go to Login
          </a>
        </div>
      </div>
    );
  }

  switch (user.role) {
    case 'admin':
      return <AdminDashboard />;
    case 'doctor':
      return <DoctorDashboard />;
    case 'patient':
      return <PatientDashboard />;
    case 'pharmacist':
      window.location.href = '/dashboard/pharmacist';
      return null;
    default:
      return <div>Unknown role.</div>;
  }
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../lib/auth';
import { db } from '../../lib/firebase';
import { collection, query, getDocs, where, doc, updateDoc, addDoc, serverTimestamp, orderBy } from 'firebase/firestore';

interface Patient {
  id: string;
  name?: string;
  email?: string;
  role?: string;
  doctorId?: string;
  records?: any[];
}

interface Appointment {
  id: string;
  patientId: string;
  patientName: string;
  doctorId: string;
  doctorName: string;
  date: string;
  time: string;
  status: 'pending' | 'scheduled' | 'completed' | 'cancelled';
  notes: string;
  recordAdded?: boolean;
}

export default function DoctorDashboard() {
  const { user } = useAuth();
  const [patients, setPatients] = useState<Patient[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filter, setFilter] = useState<'all' | 'today' | 'upcoming'>('all');
  const [loading, setLoading] = useState(true);

  // Record Modal State
  const [showRecordModal, setShowRecordModal] = useState(false);
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [selectedApptId, setSelectedApptId] = useState('');
  const [recordForm, setRecordForm] = useState({ diagnosis: '', medicines: '', notes: '' });
  const [submittingRecord, setSubmittingRecord] = useState(false);
  const [recordSuccess, setRecordSuccess] = useState('');

  const router = useRouter();

  useEffect(() => {
    if (!user) return;

    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        // Fetch Assigned Patients
        const qPatients = query(
          collection(db, 'patients'),
          where('role', '==', 'patient'),
          where('doctorId', '==', user.uid)
        );
        const querySnapshot = await getDocs(qPatients);
        const fetchedPatients: Patient[] = [];

        await Promise.all(
          querySnapshot.docs.map(async (docSnap) => {
             const pData = { ...docSnap.data(), id: docSnap.id } as Patient;
             const rSnap = await getDocs(query(collection(db, `patients/${docSnap.id}/medicalRecords`), orderBy('createdAt', 'desc')));
             const recs: any[] = [];
             rSnap.forEach(r => recs.push({ ...r.data(), id: r.id }));
             pData.records = recs;
             fetchedPatients.push(pData);
          })
        );

        setPatients(fetchedPatients);

        // Fetch Appointments mapped to this specific Doctor
        const qAppt = query(collection(db, 'appointments'), where('doctorId', '==', user.uid));
        const aSnap = await getDocs(qAppt);
        const apptsFound: Appointment[] = [];
        aSnap.forEach(a => apptsFound.push({ ...a.data(), id: a.id } as Appointment));

        // Sort effectively chronologically backwards
        apptsFound.sort((a,b) => (a.date + a.time).localeCompare(b.date + b.time));
        setAppointments(apptsFound);
      } catch (err: unknown) {
        console.error("Error fetching doctor components:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, [user]);

  const handleUpdateStatus = async (apptId: string, newStatus: Appointment['status']) => {
    try {
      const apptRef = doc(db, 'appointments', apptId);
      await updateDoc(apptRef, { status: newStatus });
      setAppointments(appointments.map(a => a.id === apptId ? { ...a, status: newStatus } : a));
    } catch (err) {
      console.error("Status update execution failed:", err);
    }
  };

  const handleAddRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatientId || !selectedApptId || !user) return;
    setSubmittingRecord(true);
    try {
      const newRec = {
        diagnosis: recordForm.diagnosis,
        medicines: recordForm.medicines,
        notes: recordForm.notes,
        doctorId: user.uid,
        createdAt: serverTimestamp()
      };
      await addDoc(collection(db, `patients/${selectedPatientId}/medicalRecords`), newRec);

      const apptRef = doc(db, 'appointments', selectedApptId);
      await updateDoc(apptRef, { status: 'completed', recordAdded: true });

      setAppointments(appointments.map(a => a.id === selectedApptId ? { ...a, status: 'completed', recordAdded: true } : a));

      setPatients(prev => prev.map(p => {
        if (p.id === selectedPatientId) {
            return {
                ...p,
                records: [{ ...newRec, createdAt: { toDate: () => new Date() } }, ...(p.records || [])]
            };
        }
        return p;
      }));

      setShowRecordModal(false);
      setRecordForm({ diagnosis: '', medicines: '', notes: '' });
      setSelectedApptId('');
      setRecordSuccess('Medical record added successfully.');
      setTimeout(() => setRecordSuccess(''), 3000);
    } catch (err) {
      console.error('Failed to save record:', err);
    } finally {
      setSubmittingRecord(false);
    }
  };

  const todayStr = new Date().toISOString().split('T')[0];

  const processedAppointments = appointments.filter(a => {
    if (a.status === 'completed' || a.recordAdded) {
      const apptDate = new Date(`${a.date}T${a.time}`);
      const oneDayAgo = new Date();
      oneDayAgo.setDate(oneDayAgo.getDate() - 1);
      if (apptDate < oneDayAgo) return false;
    }
    if (filter === 'today') return a.date === todayStr;
    if (filter === 'upcoming') return a.date >= todayStr;
    return true; // All
  });

  const processedPatients = patients.filter(p => p.role === 'patient' && p.doctorId === user.uid);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pending': return <span className="px-3 py-1 rounded-full bg-yellow-100 text-yellow-800 text-xs font-bold uppercase tracking-wider">Pending</span>;
      case 'scheduled': return <span className="px-3 py-1 rounded-full bg-blue-100 text-blue-800 text-xs font-bold uppercase tracking-wider">Scheduled</span>;
      case 'completed': return <span className="px-3 py-1 rounded-full bg-green-100 text-green-800 text-xs font-bold uppercase tracking-wider">Completed</span>;
      case 'cancelled': return <span className="px-3 py-1 rounded-full bg-red-100 text-red-800 text-xs font-bold uppercase tracking-wider">Cancelled</span>;
      default: return null;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-10">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <header className="flex flex-col md:flex-row md:items-end justify-between mb-10 gap-6">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">
              Welcome, Dr. {user?.name?.split(' ')[0] || 'Doctor'}
            </h1>
            <p className="text-gray-600">Your practice dashboard overview.</p>
          </div>
        </header>

        <div className="space-y-12">
          {recordSuccess && (
            <div className="bg-green-50 border border-green-200 text-green-800 px-4 py-3 rounded-lg mb-6 shadow-sm">
              {recordSuccess}
            </div>
          )}

          {/* Appointment Workflow Layer */}
          <section>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-900">Appointments</h2>
              <select 
                 className="border border-gray-300 rounded-lg px-4 py-2 bg-white focus:ring-2 focus:ring-blue-600 outline-none"
                 value={filter}
                 onChange={e => setFilter(e.target.value as 'all' | 'today' | 'upcoming')}
              >
                  <option value="all">View All</option>
                  <option value="today">Today Only</option>
                  <option value="upcoming">Upcoming</option>
              </select>
            </div>

            {processedAppointments.length === 0 ? (
               <div className="bg-white rounded-xl shadow-md p-10 text-center border border-gray-100">
                  <p className="text-gray-500">No appointments mapped to the specific criteria.</p>
               </div>
            ) : (
               <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {processedAppointments.map(appt => (
                    <div key={appt.id} className="bg-white rounded-xl shadow-md p-6 border border-gray-100 flex flex-col gap-4">
                        <div className="flex justify-between items-start">
                          <div>
                            <div className="text-xs text-gray-500 font-semibold mb-1 tracking-wider uppercase">{appt.date} • {appt.time}</div>
                            <h3 className="text-lg font-bold text-gray-900">{appt.patientName}</h3>
                          </div>
                          {getStatusBadge(appt.status)}
                        </div>
                        {appt.notes && <p className="text-gray-600 text-sm italic bg-gray-50 p-3 rounded-lg border border-gray-100">{appt.notes}</p>}

                        {/* Control Actions */}
                        <div className="mt-auto pt-4 flex gap-2 flex-wrap border-t border-gray-100">
                          {appt.status === 'pending' && (
                            <>
                              <button onClick={() => handleUpdateStatus(appt.id, 'scheduled')} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium">Accept</button>
                              <button onClick={() => handleUpdateStatus(appt.id, 'cancelled')} className="px-4 py-2 text-sm bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium">Reject</button>
                            </>
                          )}
                          {appt.status === 'scheduled' && !appt.recordAdded && (
                            <>
                              <button onClick={() => { setSelectedPatientId(appt.patientId); setSelectedApptId(appt.id); setShowRecordModal(true); }} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium w-full mb-2">
                                Add Medical Record & Complete
                              </button>
                              <button onClick={() => handleUpdateStatus(appt.id, 'cancelled')} className="px-4 py-2 text-sm bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium w-full">Cancel</button>
                            </>
                          )}
                          {(appt.status === 'completed' || appt.recordAdded) && (
                            <div className="w-full text-center text-sm font-medium text-gray-500 py-2 bg-gray-50 rounded-lg border border-gray-200">
                               👤 Completed & Locked
                            </div>
                          )}
                        </div>
                    </div>
                  ))}
               </div>
            )}
          </section>

          {/* Patient Records Block */}
          <section>
            <div className="flex justify-between items-end mb-6">
              <h2 className="text-2xl font-bold text-gray-900">Patient Records</h2>
              <div className="w-full md:w-80 ml-auto">
                <input
                  type="text"
                  placeholder="Search patients..."
                  className="w-full px-4 py-2 bg-white border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm"
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            {processedPatients.filter(p => p.name?.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 ? (
              <div className="bg-white rounded-xl shadow-md p-12 text-center border border-gray-100">
                <h3 className="text-lg font-medium text-gray-900 mb-1">No patients found</h3>
                <p className="text-gray-500">No patients assigned to you.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {processedPatients.filter(p => p.name?.toLowerCase().includes(searchTerm.toLowerCase())).map(patient => (
                  <div key={patient.id} className="bg-white rounded-xl shadow-md p-6 border border-gray-100 flex flex-col h-full hover:shadow-lg transition-shadow">
                    <div className="flex items-center gap-4 mb-4 pb-4 border-b border-gray-100">
                      <div className="w-12 h-12 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center font-bold text-xl uppercase flex-shrink-0">
                        {patient.name?.charAt(0) || 'P'}
                      </div>
                      <div className="overflow-hidden">
                        <h3 className="text-lg font-bold text-gray-900 truncate">{patient.name || 'Unknown'}</h3>
                        <p className="text-sm text-gray-500 truncate">{patient.email || 'No email'}</p>
                      </div>
                    </div>

                    {patient.records && patient.records.length > 0 ? (
                      <div className="text-sm text-gray-700 space-y-2 mb-4">
                        <div className="font-semibold text-gray-900 border-l-2 border-blue-500 pl-2 mb-3">
                          Latest Visit: {patient.records[0].createdAt ? (patient.records[0].createdAt.toDate ? patient.records[0].createdAt.toDate().toLocaleDateString() : new Date().toLocaleDateString()) : 'N/A'}
                        </div>
                        <p><span className="font-medium text-blue-900">Diagnosis:</span><br/> {patient.records[0].diagnosis}</p>
                        <p><span className="font-medium text-blue-900">Medicines:</span><br/> {patient.records[0].medicines}</p>
                        <p className="line-clamp-3 text-gray-500 italic mt-2"><span className="font-medium text-blue-900 not-italic">Notes:</span><br/> {patient.records[0].notes}</p>
                      </div>
                    ) : (
                      <div className="text-sm text-gray-500 italic mb-4 py-4 px-2 bg-gray-50 rounded-lg text-center border border-dashed border-gray-200">
                        No medical records explicitly on file.
                      </div>
                    )}

                    <div className="flex-grow"></div>

                    <button
                      onClick={() => router.push(`/dashboard/patients/${patient.id}`)}
                      className="w-full bg-white border border-blue-200 text-blue-600 font-medium py-2 px-4 rounded-lg hover:bg-blue-50 transition-colors mt-4"
                    >
                      View Full History
                    </button>
                  </div>
                ))}
            </div>
            )}
          </section>
        </div>

        {/* Record Overlap Modal */}
        {showRecordModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden border border-gray-100">
              <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                <h2 className="text-xl font-bold text-gray-900">Add Medical Record</h2>
                <button onClick={() => setShowRecordModal(false)} className="text-gray-400 hover:text-gray-600 text-2xl leading-none">&times;</button>
              </div>
              <div className="p-6">
                <form onSubmit={handleAddRecord} className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Diagnosis</label>
                    <input type="text" required value={recordForm.diagnosis} onChange={e => setRecordForm({...recordForm, diagnosis: e.target.value})} className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-600 outline-none" placeholder="Primary diagnosis" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Medicines</label>
                    <input type="text" required value={recordForm.medicines} onChange={e => setRecordForm({...recordForm, medicines: e.target.value})} className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-600 outline-none" placeholder="Prescription details" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                    <textarea required value={recordForm.notes} onChange={e => setRecordForm({...recordForm, notes: e.target.value})} className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-600 outline-none resize-none" rows={3} placeholder="Additional medical notes..."></textarea>
                  </div>
                  <div className="pt-4 flex gap-3">
                    <button type="button" onClick={() => setShowRecordModal(false)} disabled={submittingRecord} className="w-full py-2 px-4 border border-gray-300 text-gray-700 font-medium rounded-lg hover:bg-gray-50 transition">Cancel</button>
                    <button type="submit" disabled={submittingRecord} className="w-full py-2 px-4 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition disabled:opacity-50">
                      {submittingRecord ? 'Saving...' : 'Save Record'}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useAuth } from '../../lib/auth';
import { db } from '../../lib/firebase';
import { collection, query, getDocs, orderBy, doc, getDoc, where, addDoc, serverTimestamp } from 'firebase/firestore';

interface PatientDoc {
  id: string;
  name?: string;
  email?: string;
  phone?: string;
  userId?: string;
}

interface MedicalRecord {
  id: string;
  date?: string;
  createdAt?: any;
  diagnosis?: string;
  doctor?: string;
  medicines?: string;
  notes?: string;
}

interface Doctor {
  id: string;
  name?: string;
  email?: string;
}

interface Appointment {
  id: string;
  patientId: string;
  patientName: string;
  doctorId: string;
  doctorName: string;
  date: string;
  time: string;
  status: 'pending' | 'scheduled' | 'completed' | 'cancelled';
  notes: string;
  createdAt?: unknown;
}

interface ChatMessage {
  role: 'user' | 'ai';
  text: string;
}

export default function PatientDashboard() {
  const { user } = useAuth();
  const [patientDoc, setPatientDoc] = useState<PatientDoc | null>(null);
  const [records, setRecords] = useState<MedicalRecord[]>([]);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(true);

  // Modal State
  const [showModal, setShowModal] = useState(false);
  const [booking, setBooking] = useState(false);
  const [apptError, setApptError] = useState('');
  const [newAppt, setNewAppt] = useState({ doctorId: '', date: '', time: '', notes: '' });

  // AI Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [chatLoading, setChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages]);

  useEffect(() => {
    if (!user) return;

    const fetchData = async () => {
      try {
        setLoading(true);

        // 1. Fetch Patient Document
        const patientRef = doc(db, 'patients', user.uid);
        const pSnap = await getDoc(patientRef);

        let pData = {
          name: user.name || user.email?.split('@')[0] || 'Unknown Patient',
          email: user.email || 'Unlisted',
          phone: 'Unlisted'
        };

        if (pSnap.exists()) {
          pData = { ...pData, ...(pSnap.data() as Partial<PatientDoc>) };
        }
        setPatientDoc({ id: user.uid, ...pData });

        // 2. Fetch Medical Records
        const recordsRef = collection(db, 'patients', user.uid, 'medicalRecords');
        const rQuery = query(recordsRef, orderBy('createdAt', 'desc'));
        const rSnap = await getDocs(rQuery);

        const fetchedRecords: MedicalRecord[] = [];
        rSnap.forEach(snapDoc => {
          fetchedRecords.push({ ...(snapDoc.data() as Omit<MedicalRecord, 'id'>), id: snapDoc.id });
        });

        // Secondary sort fallback in case missing index returns arbitrary ordering
        fetchedRecords.sort((a,b) => {
           const timeA = a.createdAt?.seconds || 0;
           const timeB = b.createdAt?.seconds || 0;
           return timeB - timeA;
        });

        setRecords(fetchedRecords);

        // 3. Fetch Doctors List
        try {
          const qDoc = query(collection(db, 'users'), where('role', '==', 'doctor'));
          const dSnap = await getDocs(qDoc);
          const docsFound: Doctor[] = [];
          dSnap.forEach(d => docsFound.push({ ...(d.data() as Doctor), id: d.id }));
          setDoctors(docsFound);
        } catch(e) { console.error("Error fetching available doctors", e); } // Rules fail-safe if doctor filtering blocked

        // 4. Fetch Appointments
        const qAppt = query(collection(db, 'appointments'), where('patientId', '==', user.uid));
        const aSnap = await getDocs(qAppt);
        const apptsFound: Appointment[] = [];
        aSnap.forEach(a => apptsFound.push({ ...a.data(), id: a.id } as Appointment));

        // Local sort (date + time desc)
        apptsFound.sort((a,b) => (b.date + b.time).localeCompare(a.date + a.time));
        setAppointments(apptsFound);

      } catch (err: unknown) {
        console.error("Error fetching data:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [user]);

  const handleBook = async (e: React.FormEvent) => {
    e.preventDefault();
    setApptError('');

    if (!newAppt.doctorId || !newAppt.date || !newAppt.time) {
      setApptError("Please select a doctor, date, and time.");
      return;
    }

    const selectedDateTime = new Date(`${newAppt.date}T${newAppt.time}`);
    if (selectedDateTime < new Date()) {
      setApptError("Cannot book appointments in the past.");
      return;
    }

    setBooking(true);
    try {
      // Slot validation logically scoping exact conflicts manually matching composite indexing limits.
      const qConflict = query(collection(db, 'appointments'), where('doctorId', '==', newAppt.doctorId), where('date', '==', newAppt.date));
      const conflictSnap = await getDocs(qConflict);

      const hasConflict = conflictSnap.docs.some(docData => {
        const data = docData.data();
        return data.time === newAppt.time && data.status === 'scheduled';
      });

      if (hasConflict) {
        setApptError("This specific time slot is already scheduled with the doctor. Choose another.");
        setBooking(false);
        return;
      }

      const docObj = doctors.find(d => d.id === newAppt.doctorId);
      const payload: Omit<Appointment, 'id'> = {
        patientId: user.uid,
        patientName: patientDoc?.name || 'Patient',
        doctorId: newAppt.doctorId,
        doctorName: docObj?.name || 'Doctor',
        date: newAppt.date,
        time: newAppt.time,
        status: 'pending',
        notes: newAppt.notes,
        createdAt: serverTimestamp()
      };

      const docRef = await addDoc(collection(db, 'appointments'), payload);
      setAppointments(prev => [{ id: docRef.id, ...(payload as Omit<Appointment, 'id'>) } as Appointment, ...prev].sort((a,b) => (b.date + b.time).localeCompare(a.date + a.time)));
      setShowModal(false);
      setNewAppt({ doctorId: '', date: '', time: '', notes: '' });
    } catch (err: unknown) {
      console.error(err);
      setApptError("Failure dispatching scheduling request.");
    } finally {
      setBooking(false);
    }
  };

  const handleSendChat = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!chatInput.trim() || chatLoading) return;

    const userText = chatInput.trim();
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setChatInput('');
    setChatLoading(true);

    try {
      const res = await fetch('/api/ai-assistant', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: userText })
      });

      const data = await res.json();
      if (res.ok) {
        setChatMessages(prev => [...prev, { role: 'ai', text: data.reply }]);
      } else {
        setChatMessages(prev => [...prev, { role: 'ai', text: "Error: " + (data.error || "unavailable") }]);
      }
    } catch (err) {
      console.error("AI Fetch Failure:", err);
      setChatMessages(prev => [...prev, { role: 'ai', text: "Network error connecting to the AI system." }]);
    } finally {
      setChatLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pending': return <span className="px-3 py-1 rounded-full bg-yellow-100 text-yellow-800 text-xs font-bold uppercase tracking-wider">Pending</span>;
      case 'scheduled': return <span className="px-3 py-1 rounded-full bg-blue-100 text-blue-800 text-xs font-bold uppercase tracking-wider">Scheduled</span>;
      case 'completed': return <span className="px-3 py-1 rounded-full bg-green-100 text-green-800 text-xs font-bold uppercase tracking-wider">Completed</span>;
      case 'cancelled': return <span className="px-3 py-1 rounded-full bg-red-100 text-red-800 text-xs font-bold uppercase tracking-wider">Cancelled</span>;
      default: return null;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-10">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
        <header className="mb-10 flex flex-col sm:flex-row justify-between sm:items-end gap-6">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">
              Welcome, {patientDoc?.name?.split(' ')[0] || 'Patient'}
            </h1>
            <p className="text-gray-600">Here is your clinical dashboard and schedules.</p>
          </div>
          <button 
            onClick={() => setShowModal(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 px-6 rounded-lg shadow-md transition-colors whitespace-nowrap"
          >
            + Book Appointment
          </button>
        </header>

        {/* Modal Override Block */}
        {showModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden border border-gray-100">
              <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                <h2 className="text-xl font-bold text-gray-900">Schedule Appointment</h2>
                <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600 text-2xl leading-none">&times;</button>
              </div>
              <div className="p-6">
                {apptError && <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 text-sm rounded-lg">{apptError}</div>}
                <form onSubmit={handleBook} className="space-y-5">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Select Physician</label>
                    <select 
                      className="w-full border border-gray-300 rounded-lg px-4 py-2 bg-white focus:ring-2 focus:ring-blue-600 outline-none"
                      value={newAppt.doctorId}
                      onChange={e => setNewAppt({...newAppt, doctorId: e.target.value})}
                      disabled={booking}
                    >
                      <option value="">-- Choose a Doctor --</option>
                      {doctors.map(d => <option key={d.id} value={d.id}>Dr. {d.name}</option>)}
                    </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                      <input 
                        type="date" 
                        className="w-full border border-gray-300 rounded-lg px-4 py-2 bg-white focus:ring-2 focus:ring-blue-600 outline-none"
                        value={newAppt.date}
                        min={new Date().toISOString().split('T')[0]}
                        onChange={e => setNewAppt({...newAppt, date: e.target.value})}
                        disabled={booking}
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Time</label>
                      <input 
                        type="time" 
                        className="w-full border border-gray-300 rounded-lg px-4 py-2 bg-white focus:ring-2 focus:ring-blue-600 outline-none"
                        value={newAppt.time}
                        onChange={e => setNewAppt({...newAppt, time: e.target.value})}
                        disabled={booking}
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Reason / Notes</label>
                    <textarea 
                      className="w-full border border-gray-300 rounded-lg px-4 py-2 bg-white focus:ring-2 focus:ring-blue-600 outline-none resize-none"
                      rows={3}
                      value={newAppt.notes}
                      onChange={e => setNewAppt({...newAppt, notes: e.target.value})}
                      disabled={booking}
                      placeholder="Symptoms, requests, etc."
                    ></textarea>
                  </div>
                  <div className="pt-2 flex gap-3">
                    <button type="button" onClick={() => setShowModal(false)} disabled={booking} className="w-full py-2 px-4 border border-gray-300 text-gray-700 font-medium rounded-lg hover:bg-gray-50 transition-colors">Cancel</button>
                    <button type="submit" disabled={booking} className="w-full py-2 px-4 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50">
                      {booking ? 'Reserving...' : 'Confirm'}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        )}

        <div className="space-y-8">

          {/* Active Appointments Layer */}
          <section>
            <h2 className="text-xl font-bold text-gray-900 mb-4 border-b border-gray-200 pb-2">Upcoming Appointments</h2>
            {appointments.length === 0 ? (
                <div className="bg-white rounded-xl shadow-md p-10 text-center border border-gray-100">
                  <p className="text-gray-500">You currently have no scheduled appointments.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {appointments.map(appt => (
                    <div key={appt.id} className="bg-white rounded-xl shadow-md p-5 border border-gray-100 flex flex-col gap-3">
                      <div className="flex justify-between items-start">
                        <div className="font-bold text-gray-900 text-lg">Dr. {appt.doctorName}</div>
                        {getStatusBadge(appt.status)}
                      </div>
                      <div className="text-gray-600 font-medium flex gap-4 text-sm bg-gray-50 p-3 rounded-lg border border-gray-200">
                         <span>📅 {appt.date}</span>
                         <span>⏰ {appt.time}</span>
                      </div>
                      {appt.notes && <p className="text-gray-500 text-sm mt-1 flex-1">{appt.notes}</p>}
                    </div>
                  ))}
                </div>
            )}
          </section>

          {/* Medical Timeline Array View */}
          <section>
            <h2 className="text-xl font-bold text-gray-900 mb-4 border-b border-gray-200 pb-2">Medical Timeline</h2>
            {records.length === 0 ? (
              <div className="bg-white rounded-xl shadow-md p-12 text-center border border-gray-100">
                <div className="text-gray-400 mb-4 flex justify-center">
                  <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                </div>
                <h3 className="text-lg font-medium text-gray-900 mb-1">No records yet</h3>
                <p className="text-gray-500">Your medical history is currently empty.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {records.map(record => (
                  <div key={record.id} className="bg-white rounded-xl shadow-md p-6 border border-gray-100">
                    <div className="flex flex-col sm:flex-row justify-between mb-4">
                      <div>
                        <span className="inline-block px-3 py-1 bg-blue-50 text-blue-700 text-sm font-semibold rounded-lg mb-2">
                          {record.createdAt ? record.createdAt.toDate().toLocaleDateString() : (record.date || 'Unknown Date')}
                        </span>
                        <h3 className="text-xl font-bold text-gray-900">{record.diagnosis}</h3>
                      </div>
                      <div className="text-gray-600 font-medium mt-2 sm:mt-0">
                        {record.doctor}
                      </div>
                    </div>
                    {record.medicines && <p className="text-gray-900 font-medium my-2 bg-blue-50/50 p-3 rounded-lg border border-blue-100/50">Medicines: <span className="font-normal">{record.medicines}</span></p>}
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{record.notes}</p>
                  </div>
                ))}
              </div>
            )}
          </section>

          {/* AI Medical Assistant Array View */}
          <section className="mt-8">
            <h2 className="text-xl font-bold text-gray-900 mb-4 border-b border-gray-200 pb-2">AI Medical Assistant</h2>
            <div className="bg-white rounded-xl shadow-md border border-gray-100 p-6 flex flex-col h-[500px]">
              <div className="flex-1 overflow-y-auto mb-4 space-y-4 pr-2">
                {chatMessages.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-center text-gray-500">
                    <svg className="w-12 h-12 mb-3 text-blue-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                    <p className="font-medium">How can I assist you with your health profiling today?</p>
                    <p className="text-sm mt-1">Remember: Always consult a registered doctor for genuine diagnoses.</p>
                  </div>
                ) : (
                  chatMessages.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[80%] rounded-xl px-5 py-3 ${msg.role === 'user' ? 'bg-blue-600 text-white rounded-br-none shadow-sm' : 'bg-gray-200 text-gray-900 rounded-bl-none shadow-sm'}`}>
                        <p className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">{msg.text}</p>
                      </div>
                    </div>
                  ))
                )}
                {chatLoading && (
                  <div className="flex justify-start">
                    <div className="bg-gray-200 text-gray-500 max-w-[80%] rounded-xl rounded-bl-none px-5 py-3 shadow-sm flex gap-1 items-center">
                      <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                      <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></span>
                      <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></span>
                    </div>
                  </div>
                )}
                <div ref={chatEndRef} />
              </div>
              <form onSubmit={handleSendChat} className="flex gap-3 border-t border-gray-100 pt-4">
                <input
                  type="text"
                  placeholder="Ask a general health question..."
                  className="flex-1 border border-gray-300 rounded-lg px-4 py-3 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-shadow text-gray-800"
                  value={chatInput}
                  onChange={e => setChatInput(e.target.value)}
                  disabled={chatLoading}
                />
                <button
                  type="submit"
                  disabled={chatLoading || !chatInput.trim()}
                  className="bg-blue-600 text-white rounded-lg px-6 py-3 font-medium hover:bg-blue-700 transition-colors shadow-sm disabled:opacity-50"
                >
                  Send
                </button>
              </form>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useParams } from 'next/navigation';
import { useState, useEffect } from 'react';
import { db } from '../../../../lib/firebase';
import { useAuth } from '../../../../lib/auth';
import { doc, getDoc, collection, query, orderBy, getDocs, addDoc, serverTimestamp } from 'firebase/firestore';

interface Patient {
  id: string;
  name?: string;
  email?: string;
  phone?: string;
  userId?: string;
}

interface MedicalRecord {
  id: string;
  date?: string;
  diagnosis?: string;
  doctor?: string;
  notes?: string;
}

export default function PatientDetailPage() {
  const { id } = useParams();
  const { user } = useAuth();

  const [patient, setPatient] = useState<Patient | null>(null);
  const [records, setRecords] = useState<MedicalRecord[]>([]);
  const [loading, setLoading] = useState(true);

  const [showAddRecordForm, setShowAddRecordForm] = useState(false);
  const [newRecord, setNewRecord] = useState({ date: '', diagnosis: '', notes: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');

  const fetchPatientAndRecords = async () => {
    try {
      setLoading(true);

      const patientRef = doc(db, 'patients', id as string);
      const patientSnap = await getDoc(patientRef);

      if (!patientSnap.exists()) {
        setError('Patient not found.');
        return;
      }
      setPatient({ id: patientSnap.id, ...(patientSnap.data() as Omit<Patient, 'id'>) });

      const recordsRef = collection(db, 'patients', id as string, 'medicalRecords');
      const q = query(recordsRef, orderBy('date', 'desc'));
      const recordsSnap = await getDocs(q);

      const fetchedRecords: MedicalRecord[] = [];
      recordsSnap.forEach(snapDoc => {
        fetchedRecords.push({ id: snapDoc.id, ...(snapDoc.data() as Omit<MedicalRecord, 'id'>) });
      });
      setRecords(fetchedRecords);

    } catch (err: unknown) {
      console.error(err);
      setError('Error fetching patient data.');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    if (user && id) {
      fetchPatientAndRecords();
    }
  }, [user, id]);

  const handleAddRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.date || !newRecord.diagnosis || !newRecord.notes) return;

    setIsSubmitting(true);

    try {
      const recordsRef = collection(db, 'patients', id as string, 'medicalRecords');
      const recordPayload = {
        ...newRecord,
        doctor: user?.name || user?.email?.split('@')[0] || 'Doctor',
        createdAt: serverTimestamp()
      };

      const docRef = await addDoc(recordsRef, recordPayload);
      setRecords([{ id: docRef.id, ...recordPayload }, ...records]);

      setNewRecord({ date: '', diagnosis: '', notes: '' });
      setShowAddRecordForm(false);
    } catch (err: unknown) {
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  if (error || !patient) {
    return (
      <div className="min-h-screen bg-gray-50 p-8 flex items-center justify-center">
        <div className="bg-white p-8 rounded-xl shadow-md text-center max-w-lg w-full">
           <h2 className="text-xl font-bold text-gray-900 mb-2">Error</h2>
           <p className="text-gray-600">{error || 'Patient not found.'}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-10 px-4 sm:px-6 lg:px-8">
      <div className="max-w-5xl mx-auto">

        {/* Patient Profile Card */}
        <section className="mb-8">
          <div className="bg-white rounded-xl shadow-md p-6 border border-gray-100">
            <div className="flex items-center gap-6">
              <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center text-3xl font-bold uppercase shadow-sm">
                {patient.name?.charAt(0) || 'P'}
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900 mb-1">{patient.name || 'Unknown Patient'}</h1>
                <div className="text-gray-600 flex flex-col sm:flex-row gap-2 sm:gap-6">
                  <span>{patient.email || 'N/A'}</span>
                  <span className="hidden sm:block">•</span>
                  <span>{patient.phone || 'N/A'}</span>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Medical History Section */}
        <section>
          <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
            <h2 className="text-xl font-bold text-gray-900">Medical History</h2>
            <button 
              onClick={() => setShowAddRecordForm(!showAddRecordForm)}
              className={`font-medium py-2 px-4 rounded-lg transition-colors ${showAddRecordForm ? 'bg-gray-200 text-gray-800 hover:bg-gray-300' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md hover:shadow-lg'}`}
            >
              {showAddRecordForm ? 'Cancel Form' : 'Add New Record'}
            </button>
          </div>

          {showAddRecordForm && (
            <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 mb-8">
              <h3 className="text-lg font-bold text-gray-900 mb-4">Create Record</h3>
              <form onSubmit={handleAddRecord} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-gray-700 text-sm font-medium mb-1">Visit Date</label>
                    <input 
                      type="date" 
                      value={newRecord.date} 
                      onChange={e => setNewRecord({...newRecord, date: e.target.value})} 
                      className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 outline-none transition-all" 
                      disabled={isSubmitting}
                      required 
                    />
                  </div>
                  <div>
                    <label className="block text-gray-700 text-sm font-medium mb-1">Diagnosis</label>
                    <input 
                      type="text" 
                      placeholder="e.g. Common Cold" 
                      value={newRecord.diagnosis} 
                      onChange={e => setNewRecord({...newRecord, diagnosis: e.target.value})} 
                      className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 outline-none transition-all" 
                      disabled={isSubmitting}
                      required 
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-gray-700 text-sm font-medium mb-1">Notes</label>
                  <textarea 
                    placeholder="Patient reported symptoms..." 
                    value={newRecord.notes} 
                    onChange={e => setNewRecord({...newRecord, notes: e.target.value})} 
                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 outline-none transition-all resize-none" 
                    rows={4} 
                    disabled={isSubmitting}
                    required
                  ></textarea>
                </div>
                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 px-4 rounded-lg transition-colors disabled:opacity-50 mt-2"
                >
                  {isSubmitting ? 'Saving...' : 'Save Record'}
                </button>
              </form>
            </div>
          )}

          {records.length === 0 ? (
            <div className="bg-white rounded-xl shadow-md p-12 text-center border border-gray-100">
              <div className="text-gray-400 mb-4 flex justify-center">
                <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              </div>
              <h3 className="text-lg font-medium text-gray-900 mb-1">No records yet</h3>
              <p className="text-gray-500">There are no medical history records currently associated with this patient.</p>
            </div>
          ) : (
            <div className="space-y-4">
              {records.map(record => (
                <div key={record.id} className="p-6 rounded-xl border border-gray-100 bg-white shadow-md">
                  <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4">
                    <div>
                      <span className="inline-block px-3 py-1 bg-blue-50 text-blue-700 text-sm font-semibold rounded-lg mb-2">
                        {record.date}
                      </span>
                      <h3 className="text-lg font-bold text-gray-900">{record.diagnosis}</h3>
                    </div>
                    <div className="text-gray-600 font-medium mt-2 sm:mt-0">
                      {record.doctor}
                    </div>
                  </div>
                  <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{record.notes}</p>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import Tesseract from "tesseract.js";
import { useAuth } from '../../../lib/auth';
import { db } from '../../../lib/firebase';
import { collection, addDoc, getDocs, query, orderBy, where, serverTimestamp } from 'firebase/firestore';

interface Medicine {
  id: string;
  name: string;
  batch: string;
  expiry: string;
  stock: number;
}

interface Patient {
  id: string;
  firstName?: string;
  lastName?: string;
  name?: string;
  email?: string;
}

interface BillItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  total: number;
  medicineId: string;
}

export default function PharmacistDashboard() {
  const { user, loading } = useAuth();
  const router = useRouter();

  // Form State
  const [name, setName] = useState('');
  const [batch, setBatch] = useState('');
  const [expiry, setExpiry] = useState('');
  const [stock, setStock] = useState('');
  
  // UI State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanError, setScanError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [error, setError] = useState('');

  // Camera State
  const [showCamera, setShowCamera] = useState(false);
  const [cameraError, setCameraError] = useState('');
  const [capturedImage, setCapturedImage] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Stop camera stream safely
  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setShowCamera(false);
  };

  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  // Inventory State
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [isLoadingInventory, setIsLoadingInventory] = useState(true);

  useEffect(() => {
    if (!loading) {
      if (!user) {
        router.push('/login');
      } else if (user.role !== 'pharmacist') {
        router.push('/dashboard');
      } else {
        fetchInventory();
        fetchPatients();
      }
    }
  }, [user, loading, router]);

  // Billing State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState("");
  const [billItems, setBillItems] = useState<BillItem[]>([]);
  const [totalAmount, setTotalAmount] = useState(0);
  const [selectedMedicine, setSelectedMedicine] = useState("");
  const [billQuantity, setBillQuantity] = useState("");
  const [billPrice, setBillPrice] = useState("");
  const [isGeneratingBill, setIsGeneratingBill] = useState(false);

  const fetchPatients = async () => {
    try {
      const q = query(collection(db, 'patients'), where('role', '==', 'patient'));
      const qs = await getDocs(q);
      const pts: Patient[] = [];
      qs.forEach(doc => {
        pts.push({ id: doc.id, ...doc.data() } as Patient);
      });
      setPatients(pts);
    } catch (err) {
      console.error("Failed to fetch patients", err);
      try {
        const fbQ = collection(db, 'patients');
        const fbSnap = await getDocs(fbQ);
        const fbPts: Patient[] = [];
        fbSnap.forEach(doc => fbPts.push({ id: doc.id, ...doc.data() } as Patient));
        setPatients(fbPts);
      } catch (inner) {}
    }
  };

  const fetchInventory = async () => {
    if (!user) return;
    setIsLoadingInventory(true);
    try {
      const q = query(
        collection(db, `inventory/${user.uid}/medicines`),
        orderBy('createdAt', 'desc')
      );
      const querySnapshot = await getDocs(q);
      const meds: Medicine[] = [];
      querySnapshot.forEach((doc) => {
        meds.push({ id: doc.id, ...doc.data() } as Medicine);
      });
      setMedicines(meds);
    } catch (err) {
      console.error('Failed to fetch inventory:', err);
      // Fallback if query indexing fails or anything else
      try {
        const fallbackQ = collection(db, `inventory/${user.uid}/medicines`);
        const fallbackSnapshot = await getDocs(fallbackQ);
        const fallbackMeds: Medicine[] = [];
        fallbackSnapshot.forEach(doc => {
          fallbackMeds.push({ id: doc.id, ...doc.data() } as Medicine);
        });
        // Sort manually
        fallbackMeds.sort((a: any, b: any) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0));
        setMedicines(fallbackMeds);
      } catch (innerErr) {
        console.error('Fallback query failed', innerErr);
      }
    } finally {
      setIsLoadingInventory(false);
    }
  };

  const handleAddBillItem = () => {
    if (!selectedMedicine || !billQuantity || !billPrice) {
      setError("Please select a medicine, quantity, and price.");
      setTimeout(() => setError(""), 3000);
      return;
    }
    const med = medicines.find(m => m.id === selectedMedicine);
    if (!med) return;
    
    const qty = parseInt(billQuantity, 10);
    const price = parseFloat(billPrice);
    
    if (qty <= 0 || price < 0) {
      setError("Quantity and price must be positive.");
      setTimeout(() => setError(""), 3000);
      return;
    }
    
    if (qty > med.stock) {
      setError(`Warning: Quantity exceeds current stock (${med.stock}).`);
      setTimeout(() => setError(""), 3000);
    }
    
    const newItem = {
      id: Date.now().toString(),
      medicineId: med.id,
      name: med.name,
      price,
      quantity: qty,
      total: price * qty
    };
    
    const newItems = [...billItems, newItem];
    setBillItems(newItems);
    setTotalAmount(newItems.reduce((sum, item) => sum + item.total, 0));
    
    setSelectedMedicine("");
    setBillQuantity("");
    setBillPrice("");
  };

  const handleGenerateBill = async () => {
    if (!selectedPatient || billItems.length === 0) return;
    setIsGeneratingBill(true);
    try {
      const billData = {
        patientId: selectedPatient,
        items: billItems,
        totalAmount,
        createdAt: serverTimestamp(),
        pharmacistId: user?.uid
      };
      
      await addDoc(collection(db, 'bills'), billData);
      await addDoc(collection(db, `patients/${selectedPatient}/bills`), billData);
      
      setBillItems([]);
      setTotalAmount(0);
      setSelectedPatient("");
      setSuccessMessage("Bill generated securely and saved!");
      setTimeout(() => setSuccessMessage(""), 3000);
    } catch (err: any) {
      setError(err.message || "Failed to generate bill.");
      setTimeout(() => setError(""), 3000);
    } finally {
      setIsGeneratingBill(false);
    }
  };

  const handleAddMedicine = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    if (!name || !batch || !expiry || !stock) {
      setError('Please fill out all fields.');
      return;
    }
    
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    try {
      await addDoc(collection(db, `inventory/${user.uid}/medicines`), {
        name,
        batch,
        expiry,
        stock: parseInt(stock, 10),
        createdBy: user.uid,
        createdAt: new Date()
      });
      
      setSuccessMessage('Medicine added successfully!');
      setName('');
      setBatch('');
      setExpiry('');
      setStock('');
      
      // Refresh inventory
      fetchInventory();
      
      // Clear message after 3 seconds
      setTimeout(() => setSuccessMessage(''), 3000);
    } catch (err: any) {
      setError(err.message || 'Failed to add medicine.');
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleScan = async (image: string) => {
    try {
      setIsScanning(true);
      setScanError("");

      const { data: { text } } = await Tesseract.recognize(
        image,
        "eng",
        {
          tessedit_char_whitelist:
            "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
        } as any
      );

      console.log("OCR TEXT:", text);

      // =====================
      // TEXT CLEANING
      // =====================
      let cleanText = text
        .replace(/\n/g, " ")
        .replace(/\s+/g, " ")
        .toLowerCase();

      console.log("CLEAN TEXT:", cleanText);

      // =====================
      // MEDICINE NAME DETECTION
      // =====================
      const knownMedicines = [
        "calpol",
        "paracetamol",
        "crocin",
        "dolo",
        "ibuprofen"
      ];

      let name = "";

      for (let med of knownMedicines) {
        if (cleanText.includes(med)) {
          name = med.toUpperCase();
          break;
        }
      }

      // fallback
      if (!name && cleanText.includes("500") && cleanText.includes("mg")) {
        name = "PARACETAMOL 500";
      }

      // =====================
      // BATCH DETECTION
      // =====================
      const batchMatch = cleanText.match(/[a-z]{2,}\d{2,}/i);
      const batch = batchMatch ? batchMatch[0].toUpperCase() : "";

      // =====================
      // EXPIRY DETECTION
      // =====================
      const expiryMatch = cleanText.match(
        /(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*\s?\d{2}/i
      );

      const expiry = expiryMatch ? expiryMatch[0] : "";

      console.log("EXTRACTED:", { name, batch, expiry });

      // =====================
      // AUTO FILL (PARTIAL SAFE)
      // =====================
      setName(name || "");
      setBatch(batch || "");
      setExpiry(expiry || "");

    } catch (error) {
      console.error("OCR ERROR:", error);
      setScanError("Unable to detect. Please enter manually.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64 = reader.result as string;
        setCapturedImage(base64);
        handleScan(base64);
      };
      
      reader.onerror = () => {
        setScanError('File read failed');
      };
    } finally {
      e.target.value = '';
    }
  };

  const startCamera = async () => {
    setShowCamera(true);
    setCameraError('');
    setCapturedImage('');
    setScanError('');
    setSuccessMessage('');
    setError('');
    
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error(err);
      setCameraError('Camera permission denied or camera not available.');
    }
  };

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      
      const context = canvas.getContext('2d');
      if (context) {
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
        handleScan(base64);
      }
    }
  };

  if (loading || !user || user.role !== 'pharmacist') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="w-16 h-16 border-4 border-emerald-200 border-t-emerald-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 p-6 md:p-12 font-sans text-slate-800">
      <div className="max-w-6xl mx-auto space-y-8">
        
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-4xl font-extrabold text-slate-800 tracking-tight">
              Pharmacist <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-500 to-teal-600">Inventory</span>
            </h1>
            <p className="text-slate-500 mt-2 text-lg">Manage medicines securely from your personal dashboard.</p>
          </div>
          <button 
            onClick={() => router.push('/dashboard')}
            className="px-5 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 hover:text-slate-900 transition-all font-medium shadow-sm"
          >
            ← Back to Router
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          
          {/* Add Medicine Form (Left Column) */}
          <div className="bg-white rounded-3xl p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 lg:col-span-1 h-fit">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
              <h2 className="text-2xl font-bold flex items-center gap-3">
                <span className="w-10 h-10 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                </span>
                Add Medicine
              </h2>
              
              <div className="flex gap-2">
                <button 
                  type="button"
                  onClick={startCamera}
                  disabled={isScanning || showCamera}
                  className="cursor-pointer inline-flex items-center justify-center bg-emerald-50 text-emerald-700 hover:bg-emerald-100 px-3 py-2 rounded-lg font-semibold text-sm transition-colors disabled:opacity-50"
                  title="Use Camera"
                >
                  <svg className="w-5 h-5 mr-1.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                  Use Camera
                </button>

                <label className="cursor-pointer inline-flex items-center justify-center bg-blue-50 text-blue-600 hover:bg-blue-100 px-3 py-2 rounded-lg font-semibold text-sm transition-colors" title="Upload Image">
                  {isScanning && !showCamera ? (
                    <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  ) : (
                    <>
                      <svg className="w-5 h-5 mr-1.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"></path></svg>
                      Upload Image
                    </>
                  )}
                  <input type="file" accept="image/*" onChange={handleScanImage} className="hidden" disabled={isScanning || showCamera} />
                </label>
              </div>
            </div>

            {showCamera && (
              <div className="mb-6 p-4 rounded-xl bg-slate-50 border border-slate-200">
                <div className="relative rounded-lg overflow-hidden bg-black mb-4 aspect-video flex-shrink-0 flex items-center justify-center">
                  <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover"></video>
                  <canvas ref={canvasRef} className="hidden"></canvas>
                  {/* Overlay for scanning frame hint could go here */}
                </div>
                {cameraError && <p className="text-red-600 text-sm font-medium mb-3 bg-red-50 p-3 rounded-lg border border-red-100">{cameraError}</p>}
                <div className="flex gap-3 justify-end mt-2">
                  <button type="button" onClick={stopCamera} className="px-4 py-2 text-slate-600 bg-white border border-slate-300 hover:bg-slate-50 rounded-lg font-medium text-sm transition-colors shadow-sm">Cancel</button>
                  <button type="button" onClick={captureImage} disabled={!!cameraError} className="px-5 py-2 text-white bg-emerald-600 hover:bg-emerald-700 rounded-lg font-medium text-sm transition-colors flex items-center shadow-md shadow-emerald-200 disabled:opacity-50">
                    Capture Image
                  </button>
                </div>
              </div>
            )}

            {capturedImage && !showCamera && (
              <div className="mb-6 relative w-28 h-28 rounded-xl overflow-hidden border-2 border-slate-200 shadow-sm mx-auto bg-slate-100 flex items-center justify-center">
                <img src={capturedImage} alt="Captured preview" className={`w-full h-full object-cover transition-opacity ${isScanning ? 'opacity-50' : 'opacity-100'}`} />
                {isScanning && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <svg className="w-8 h-8 animate-spin text-blue-600 drop-shadow-md" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  </div>
                )}
                {!isScanning && (
                  <button type="button" onClick={() => { setCapturedImage(''); }} className="absolute top-1.5 right-1.5 bg-black/60 text-white rounded-full p-1.5 hover:bg-black/80 transition-colors shadow-sm backdrop-blur-sm">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                  </button>
                )}
              </div>
            )}



            {error && (
              <div className="mb-6 p-4 rounded-xl bg-red-50 text-red-700 text-sm font-medium border border-red-100 flex items-start gap-3">
                <svg className="w-5 h-5 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                {error}
              </div>
            )}
            
            {scanError && (
              <div className="mb-6 p-4 rounded-xl bg-orange-50 text-orange-700 text-sm font-medium border border-orange-100 flex items-start gap-3">
                <svg className="w-5 h-5 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                {scanError}
              </div>
            )}
            
            {successMessage && (
              <div className="mb-6 p-4 rounded-xl bg-emerald-50 text-emerald-700 text-sm font-medium border border-emerald-100 flex items-start gap-3">
                <svg className="w-5 h-5 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                {successMessage}
              </div>
            )}

            <form onSubmit={handleAddMedicine} className="space-y-5">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Medicine Name</label>
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                  placeholder="e.g. Paracetamol 500mg"
                />
              </div>
              
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Batch Number</label>
                <input 
                  type="text" 
                  value={batch}
                  onChange={(e) => setBatch(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                  placeholder="e.g. BATCH-2023X"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Expiry Date</label>
                  <input 
                    type="month" 
                    value={expiry}
                    onChange={(e) => setExpiry(e.target.value)}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Stock Qty</label>
                  <input 
                    type="number" 
                    min="0"
                    value={stock}
                    onChange={(e) => setStock(e.target.value)}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                    placeholder="e.g. 100"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={isSubmitting}
                className="w-full py-3.5 px-4 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-bold rounded-xl shadow-[0_4px_14px_0_rgba(16,185,129,0.39)] hover:shadow-[0_6px_20px_rgba(16,185,129,0.23)] transition-all disabled:opacity-70 disabled:cursor-not-allowed mt-2"
              >
                {isSubmitting ? 'Adding...' : 'Add to Inventory'}
              </button>
            </form>
          </div>

          {/* Inventory Display (Right Column) */}
          <div className="bg-white rounded-3xl p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 lg:col-span-2 flex flex-col min-h-[500px]">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold flex items-center gap-3">
                <span className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-blue-600">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 002-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg>
                </span>
                Current Inventory
              </h2>
              <div className="px-4 py-1.5 bg-slate-100 text-slate-600 font-semibold rounded-full text-sm">
                {medicines.length} Items
              </div>
            </div>

            {isLoadingInventory ? (
              <div className="flex-1 flex flex-col items-center justify-center space-y-4">
                <div className="w-10 h-10 border-4 border-slate-100 border-t-emerald-500 rounded-full animate-spin"></div>
                <p className="text-slate-500 font-medium animate-pulse">Loading stock data...</p>
              </div>
            ) : medicines.length === 0 ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center p-8 border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50/50">
                <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center text-slate-300 shadow-sm mb-4">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4"></path></svg>
                </div>
                <h3 className="text-xl font-bold text-slate-700 mb-2">Inventory Empty</h3>
                <p className="text-slate-500 max-w-sm">No medicines added yet. Use the form on the left to start building your inventory.</p>
              </div>
            ) : (
              <div className="flex-1 overflow-x-auto -mx-8 px-8">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="border-b border-slate-100 text-slate-400 text-sm uppercase tracking-wider font-semibold">
                      <th className="pb-4 pt-1 px-4 cursor-default">Medicine Name</th>
                      <th className="pb-4 pt-1 px-4 cursor-default text-center">Batch No.</th>
                      <th className="pb-4 pt-1 px-4 cursor-default text-center">Expiry</th>
                      <th className="pb-4 pt-1 px-4 cursor-default text-right">Stock</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {medicines.map((med) => {
                      const today = new Date();
                      const expiryDate = new Date(med.expiry);
                      const diffDays = (expiryDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);
                      
                      const isExpiringSoon = diffDays < 30;
                      const isLowStock = med.stock < 10;
                      
                      const rowClass = isLowStock 
                        ? 'bg-red-50/40 hover:bg-red-50/60' 
                        : isExpiringSoon 
                          ? 'bg-yellow-50/40 hover:bg-yellow-50/60' 
                          : 'hover:bg-slate-50/80';

                      return (
                        <tr key={med.id} className={`${rowClass} transition-colors group`}>
                          <td className="py-4 px-4 whitespace-nowrap">
                            <div className="flex flex-col">
                               <span className="font-bold text-slate-800">{med.name}</span>
                               <div className="flex gap-2 mt-1">
                                  {isExpiringSoon && <span className="text-[10px] font-bold uppercase tracking-wider text-yellow-600 bg-yellow-100 px-2 py-0.5 rounded-sm">Expiring Soon</span>}
                                  {isLowStock && <span className="text-[10px] font-bold uppercase tracking-wider text-red-600 bg-red-100 px-2 py-0.5 rounded-sm">Low Stock</span>}
                               </div>
                            </div>
                          </td>
                          <td className="py-4 px-4 text-center">
                            <span className="inline-flex items-center px-2.5 py-1 rounded-md bg-white border border-slate-200 text-slate-600 text-xs font-mono font-medium shadow-sm">
                              {med.batch}
                            </span>
                          </td>
                          <td className="py-4 px-4 text-center">
                            <span className={`${
                              isExpiringSoon ? 'text-yellow-700 font-bold' : 'text-slate-500 font-medium'
                            }`}>
                              {med.expiry || 'N/A'}
                            </span>
                          </td>
                          <td className="py-4 px-4 text-right">
                            <span className={`inline-flex items-center justify-center min-w-[3rem] px-3 py-1.5 rounded-full text-sm font-bold shadow-sm ${
                              isLowStock ? 'bg-red-100 text-red-700 border border-red-200' : 'bg-white border border-emerald-100 text-emerald-600'
                            }`}>
                              {med.stock}
                            </span>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
            
          </div>

        </div>

        {/* Billing System */}
        <div className="bg-white rounded-3xl p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 mt-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-2xl font-bold flex items-center gap-3">
              <span className="w-10 h-10 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0z"></path></svg>
              </span>
              Billing & Checkout
            </h2>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
            {/* Input Form */}
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Select Patient</label>
                <select
                  value={selectedPatient}
                  onChange={(e) => setSelectedPatient(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                >
                  <option value="">-- Choose Patient --</option>
                  {patients.map(p => (
                    <option key={p.id} value={p.id}>
                      {p.name || `${p.firstName || ''} ${p.lastName || ''}`.trim() || p.email || p.id}
                    </option>
                  ))}
                </select>
              </div>

              <div className="p-5 bg-slate-50 border border-slate-200 rounded-2xl space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Select Medicine</label>
                  <select
                    value={selectedMedicine}
                    onChange={(e) => setSelectedMedicine(e.target.value)}
                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  >
                    <option value="">-- Choose Medicine --</option>
                    {medicines.filter(m => m.stock > 0).map(m => (
                      <option key={m.id} value={m.id}>
                        {m.name} (Stock: {m.stock})
                      </option>
                    ))}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Quantity</label>
                    <input
                      type="number"
                      min="1"
                      value={billQuantity}
                      onChange={(e) => setBillQuantity(e.target.value)}
                      placeholder="Qty"
                      className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Price per unit</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={billPrice}
                      onChange={(e) => setBillPrice(e.target.value)}
                      placeholder="$0.00"
                      className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                </div>

                <button
                  type="button"
                  onClick={handleAddBillItem}
                  className="w-full py-3 bg-slate-800 hover:bg-slate-900 text-white font-bold rounded-xl shadow-md transition-colors"
                >
                  Add Item to Bill
                </button>
              </div>
            </div>

            {/* Bill Summary */}
            <div className="flex flex-col bg-slate-50 border border-slate-200 rounded-2xl p-6 min-h-[300px]">
              <h3 className="font-bold text-slate-800 mb-4 text-lg border-b border-slate-200 pb-2">Current Bill</h3>
              
              {billItems.length === 0 ? (
                <div className="flex-1 flex items-center justify-center text-slate-400 font-medium">
                  No items added yet
                </div>
              ) : (
                <div className="flex-1 overflow-y-auto space-y-3 mb-4 max-h-[300px]">
                  {billItems.map(item => (
                    <div key={item.id} className="flex justify-between items-center bg-white p-3 rounded-lg shadow-sm border border-slate-100">
                      <div>
                        <p className="font-semibold text-slate-800 text-sm">{item.name}</p>
                        <p className="text-xs text-slate-500">{item.quantity} x ${item.price.toFixed(2)}</p>
                      </div>
                      <p className="font-bold text-slate-800">${item.total.toFixed(2)}</p>
                    </div>
                  ))}
                </div>
              )}

              <div className="border-t border-slate-200 pt-4 mt-auto">
                <div className="flex justify-between items-center mb-6">
                  <span className="font-bold text-slate-600">Total Amount</span>
                  <span className="font-extrabold text-2xl text-slate-800">${totalAmount.toFixed(2)}</span>
                </div>
                
                <button
                  onClick={handleGenerateBill}
                  disabled={billItems.length === 0 || !selectedPatient || isGeneratingBill}
                  className="w-full py-4 bg-gradient-to-r from-indigo-500 to-blue-600 hover:from-indigo-600 hover:to-blue-700 text-white font-bold rounded-xl shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isGeneratingBill ? "Generating..." : "Generate Bill & Save"}
                </button>
              </div>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}
